// Recebe o payload do Admin/Mensalli e gera 1 item por usuário com mensagem pronta
const body = $input.first().json.body || {};
const usuarios = body.usuarios || [];
const grupo = body.grupo || 'trial';   // trial | churn | venc_d3 | venc_hoje | venc_vencido
const oferta = body.oferta || 'extensao_14_dias';

// Helpers de data e dinheiro
const formatarBR = (iso) => {
  if (!iso) return '';
  const d = new Date(iso);
  return d.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric', timeZone: 'America/Sao_Paulo' });
};
const diasAteVencimento = (iso) => {
  if (!iso) return null;
  const hoje = new Date(); hoje.setHours(0,0,0,0);
  const venc = new Date(iso); venc.setHours(0,0,0,0);
  return Math.round((venc - hoje) / (1000 * 60 * 60 * 24));
};
const formatarBRL = (n) => {
  if (n === null || n === undefined || isNaN(n)) return '';
  return Number(n).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};
const pixAdmin = body.chave_pix || '';

// Templates por grupo — edite à vontade
const templatesOferta = {
  trial: {
    extensao_7_dias:
      'Oi {{nome}}! 👋\n\nVi que seu teste do Mensalli expirou esses dias e queria fazer uma cortesia: tô liberando *+7 dias* extras pra você terminar de configurar.\n\nDá pra automatizar suas cobranças por WhatsApp em poucos cliques. Posso reativar sua conta?',

    extensao_14_dias:
      'Oi {{nome}}! 👋\n\nNotei que o trial do Mensalli encerrou e queria te dar mais uma chance: vou estender *+14 dias gratuitos* pra você testar com calma — sem compromisso.\n\nSe quiser, eu reativo já. É só responder "sim".',

    desconto_50_1mes:
      'Oi {{nome}}! 👋\n\nSeu teste do Mensalli acabou e tô com uma oferta que fecha hoje: *50% OFF no primeiro mês* do plano *{{plano}}*.\n\nDe R$ {{valor}} por *R$ {{valor_com_desconto}}* só no 1º mês. É a melhor forma de validar o sistema cobrando seus alunos no automático sem pagar tudo de uma.\n\n💳 *Pix (chave):*\n{{pix}}\n\nÉ só me chamar com o comprovante que ativo na hora.',

    desconto_30_3meses:
      'Oi {{nome}}! 👋\n\nTô voltando aqui porque seu teste do Mensalli ficou parado. Pra te chamar de volta sem peso, separei *30% OFF nos 3 primeiros meses* do plano *{{plano}}*.\n\nDe R$ {{valor}} por *R$ {{valor_com_desconto}}/mês* nos 3 primeiros meses.\n\n💳 *Pix (chave):*\n{{pix}}\n\nQuer que eu libere o cupom? Manda comprovante e ativo.'
  },
  churn: {
    extensao_7_dias:
      'Oi {{nome}}! 👋\n\nFaz um tempo que você não tá com a gente no Mensalli e a gente quer te ter de volta. Liberei *7 dias grátis* pra você reativar e voltar a usar agora.\n\nSeus dados continuam aqui, é só dar o sim. Posso ativar?',

    extensao_14_dias:
      'Oi {{nome}}! 👋\n\nSentimos sua falta no Mensalli. Pra você voltar sem pressão, abri *14 dias grátis* — você reativa, testa de novo, e só decide depois.\n\nQuer que eu solte agora?',

    desconto_50_proximo_mes:
      'Oi {{nome}}! 👋\n\nPra te ter de volta no Mensalli, separei uma oferta de retorno: *50% OFF no próximo mês* do seu plano *{{plano}}*.\n\nDe R$ {{valor}} por *R$ {{valor_com_desconto}}* na renovação. Você volta a cobrar seus alunos no automático pagando metade.\n\n💳 *Pix (chave):*\n{{pix}}\n\nManda comprovante quando pagar e eu ativo na hora.',

    desconto_30_proximo_mes:
      'Oi {{nome}}! 👋\n\nTô voltando aqui pra te oferecer um retorno suave ao Mensalli: *30% OFF no próximo mês* do plano *{{plano}}*.\n\nDe R$ {{valor}} por *R$ {{valor_com_desconto}}*. Mesmo plano, mesmos dados, só com um descontinho pra facilitar a volta.\n\n💳 *Pix (chave):*\n{{pix}}\n\nQuer que eu prepare?'
  }
};

// Templates de lembrete (sem oferta — usam {{vencimento}}, {{dias}}, {{plano}}, {{valor}}, {{pix}})
const templatesLembrete = {
  venc_d3:
    'Oi {{nome}}! 👋\n\nPassando aqui pra avisar que seu plano *{{plano}}* (R$ {{valor}}/mês) no Mensalli vence em *{{dias}} dias* ({{vencimento}}).\n\nPra evitar interrupção do serviço e suas cobranças automáticas continuarem rodando, confirma o pagamento até a data.\n\n💳 *Pix (chave):*\n{{pix}}\n\nQualquer dúvida, é só chamar.',

  venc_hoje:
    'Oi {{nome}}! 👋\n\nSeu plano *{{plano}}* (R$ {{valor}}) no Mensalli vence *hoje* ({{vencimento}}).\n\nPra suas cobranças continuarem rodando sem interrupção, garante o pagamento ainda hoje, beleza?\n\n💳 *Pix (chave):*\n{{pix}}\n\nQualquer problema, me chama agora.',

  venc_vencido:
    'Oi {{nome}}! 👋\n\nSeu plano *{{plano}}* (R$ {{valor}}) no Mensalli venceu há *{{dias_atraso}} dia(s)* ({{vencimento}}) e ainda não vi a renovação.\n\nPra reativar o sistema e suas automações de cobrança voltarem a rodar, é só fazer o pagamento agora.\n\n💳 *Pix (chave):*\n{{pix}}\n\nPosso te ajudar com algo?'
};

let tmpl;
if (grupo.startsWith('venc_')) {
  tmpl = templatesLembrete[grupo] || templatesLembrete.venc_hoje;
} else {
  const tmplDoGrupo = templatesOferta[grupo] || templatesOferta.trial;
  tmpl = tmplDoGrupo[oferta] || tmplDoGrupo.extensao_14_dias || templatesOferta.trial.extensao_14_dias;
}

const itens = [];
for (const u of usuarios) {
  const telLimpo = String(u.telefone || '').replace(/\D/g, '');
  if (telLimpo.length < 10) continue; // pula sem telefone válido
  const telE164 = telLimpo.startsWith('55') ? telLimpo : `55${telLimpo}`;
  const primeiroNome = (u.nome_completo || u.nome_empresa || 'Cliente').split(' ')[0];
  const dias = diasAteVencimento(u.plano_vencimento);
  const diasAtraso = dias !== null && dias < 0 ? Math.abs(dias) : '';
  const valorCheio = Number(u.plano_valor || 0);
  // Calcula valor com desconto baseado na oferta escolhida
  let valorComDesconto = valorCheio;
  if (oferta === 'desconto_50_1mes' || oferta === 'desconto_50_proximo_mes') valorComDesconto = valorCheio * 0.5;
  else if (oferta === 'desconto_30_3meses' || oferta === 'desconto_30_proximo_mes') valorComDesconto = valorCheio * 0.7;
  const mensagem = tmpl
    .replace(/\{\{nome\}\}/g, primeiroNome)
    .replace(/\{\{email\}\}/g, u.email || '')
    .replace(/\{\{vencimento\}\}/g, formatarBR(u.plano_vencimento))
    .replace(/\{\{dias\}\}/g, dias !== null && dias > 0 ? String(dias) : '')
    .replace(/\{\{dias_atraso\}\}/g, String(diasAtraso))
    .replace(/\{\{plano\}\}/g, u.plano_nome || 'Starter')
    .replace(/\{\{valor\}\}/g, formatarBRL(valorCheio))
    .replace(/\{\{valor_com_desconto\}\}/g, formatarBRL(valorComDesconto))
    .replace(/\{\{pix\}\}/g, pixAdmin || '(PIX não configurado)');
  itens.push({
    json: {
      id: u.id,
      email: u.email,
      nome: primeiroNome,
      nome_completo: u.nome_completo,
      nome_empresa: u.nome_empresa,
      telefone_e164: telE164,
      mensagem,
      grupo,
      oferta,
      oferta_label: body.oferta_label,
      evolution_api_url: body.evolution_api_url,
      evolution_api_key: body.evolution_api_key
    }
  });
}
return itens;
